#!/usr/bin/env python3
"""
Dependency Management Script for Python Projects
Manages requirements.txt with hashes and Poetry lock files
"""

import os
import sys
import subprocess
import hashlib
import json
from pathlib import Path
from typing import List, Dict, Optional

class DependencyManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root)
        self.requirements_file = self.project_root / "requirements.txt"
        self.poetry_lock_file = self.project_root / "poetry.lock"
        self.pyproject_file = self.project_root / "pyproject.toml"
        
    def generate_requirements_with_hashes(self) -> None:
        """Generate requirements.txt with hashes using pip-compile"""
        try:
            subprocess.run([
                "pip-compile", 
                "--generate-hashes",
                "--output-file", 
                str(self.requirements_file),
                "pyproject.toml"
            ], check=True, capture_output=True)
            print("✓ Generated requirements.txt with hashes")
        except subprocess.CalledProcessError as e:
            print(f"✗ Error generating requirements: {e}")
            sys.exit(1)
            
    def update_requirements(self) -> None:
        """Update requirements.txt with latest versions"""
        try:
            subprocess.run([
                "pip-compile", 
                "--upgrade",
                "--generate-hashes",
                "--output-file", 
                str(self.requirements_file),
                "pyproject.toml"
            ], check=True, capture_output=True)
            print("✓ Updated requirements.txt with latest versions")
        except subprocess.CalledProcessError as e:
            print(f"✗ Error updating requirements: {e}")
            sys.exit(1)
            
    def verify_requirements_integrity(self) -> bool:
        """Verify integrity of requirements.txt"""
        if not self.requirements_file.exists():
            print("✗ requirements.txt not found")
            return False
            
        try:
            with open(self.requirements_file, 'r') as f:
                content = f.read()
                
            # Check for hash presence
            lines = content.strip().split('\n')
            for line in lines:
                if line and not line.startswith('#') and not line.startswith('-'):
                    if not any(hash_alg in line for hash_alg in ['sha256:', 'sha384:', 'sha512:']):
                        print(f"✗ Missing hash in line: {line}")
                        return False
                        
            print("✓ Requirements.txt integrity verified")
            return True
            
        except Exception as e:
            print(f"✗ Error verifying requirements: {e}")
            return False
            
    def generate_poetry_lock(self) -> None:
        """Generate or update poetry.lock file"""
        try:
            subprocess.run([
                "poetry", "lock", "--no-update"
            ], check=True, capture_output=True)
            print("✓ Generated poetry.lock file")
        except subprocess.CalledProcessError as e:
            print(f"✗ Error generating poetry.lock: {e}")
            sys.exit(1)
            
    def update_poetry_lock(self) -> None:
        """Update poetry.lock with latest versions"""
        try:
            subprocess.run([
                "poetry", "lock", "--update"
            ], check=True, capture_output=True)
            print("✓ Updated poetry.lock file")
        except subprocess.CalledProcessError as e:
            print(f"✗ Error updating poetry.lock: {e}")
            sys.exit(1)
            
    def verify_poetry_lock_integrity(self) -> bool:
        """Verify integrity of poetry.lock"""
        if not self.poetry_lock_file.exists():
            print("✗ poetry.lock not found")
            return False
            
        try:
            with open(self.poetry_lock_file, 'r') as f:
                content = f.read()
                
            # Basic integrity check
            if '[metadata]' not in content:
                print("✗ Invalid poetry.lock format")
                return False
                
            print("✓ Poetry.lock integrity verified")
            return True
            
        except Exception as e:
            print(f"✗ Error verifying poetry.lock: {e}")
            return False
            
    def install_requirements(self, use_hash_verification: bool = True) -> None:
        """Install dependencies from requirements.txt"""
        if not self.requirements_file.exists():
            print("✗ requirements.txt not found")
            sys.exit(1)
            
        try:
            cmd = ["pip", "install", "-r", str(self.requirements_file)]
            if use_hash_verification:
                cmd.append("--require-hashes")
                
            subprocess.run(cmd, check=True, capture_output=True)
            print("✓ Dependencies installed successfully")
        except subprocess.CalledProcessError as e:
            print(f"✗ Error installing dependencies: {e}")
            sys.exit(1)
            
    def install_from_poetry(self) -> None:
        """Install dependencies from poetry.lock"""
        if not self.poetry_lock_file.exists():
            print("✗ poetry.lock not found")
            sys.exit(1)
            
        try:
            subprocess.run([
                "poetry", "install", "--no-root"
            ], check=True, capture_output=True)
            print("✓ Dependencies installed from poetry.lock")
        except subprocess.CalledProcessError as e:
            print(f"✗ Error installing from poetry: {e}")
            sys.exit(1)
            
    def get_dependency_info(self) -> Dict:
        """Get dependency information from requirements.txt"""
        if not self.requirements_file.exists():
            return {}
            
        deps = {}
        try:
            with open(self.requirements_file, 'r') as f:
                for line in f:
                    line = line.strip()
                    if line and not line.startswith('#') and not line.startswith('-'):
                        if '==' in line:
                            pkg, version = line.split('==', 1)
                            deps[pkg.strip()] = version.strip()
        except Exception as e:
            print(f"Error reading requirements: {e}")
            
        return deps
        
    def get_poetry_dependencies(self) -> Dict:
        """Get dependencies from poetry.lock"""
        if not self.poetry_lock_file.exists():
            return {}
            
        deps = {}
        try:
            with open(self.poetry_lock_file, 'r') as f:
                content = f.read()
                
            # Simple parsing for version info
            lines = content.split('\n')
            current_package = None
            for line in lines:
                if line.startswith('[[package]]'):
                    current_package = None
                elif line.startswith('name = ') and current_package is None:
                    current_package = line.split(' = ')[1].strip('"')
                elif line.startswith('version = ') and current_package:
                    version = line.split(' = ')[1].strip('"')
                    deps[current_package] = version
                    
        except Exception as e:
            print(f"Error reading poetry.lock: {e}")
            
        return deps

def main():
    dm = DependencyManager()
    
    if len(sys.argv) < 2:
        print("Usage: python dependency_manager.py [generate|update|verify|install|poetry]")
        sys.exit(1)
        
    command = sys.argv[1]
    
    if command == "generate":
        dm.generate_requirements_with_hashes()
        dm.generate_poetry_lock()
    elif command == "update":
        dm.update_requirements()
        dm.update_poetry_lock()
    elif command == "verify":
        dm.verify_requirements_integrity()
        dm.verify_poetry_lock_integrity()
    elif command == "install":
        dm.install_requirements()
    elif command == "poetry":
        dm.install_from_poetry()
    else:
        print("Unknown command")
        sys.exit(1)

if __name__ == "__main__":
    main()